import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.encoder.Encode;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");
        PrintWriter out = response.getWriter();

        out.println("<html>");
        out.println("<head><title>Secure Code Example</title></head>");
        out.println("<body>");
        // Sanitize and escape user input before embedding it in the HTML response
        out.println("<h1>Welcome " + Encode.forHtml(userInput) + "</h1>");
        out.println("</body>");
        out.println("</html>");

    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
